mapper.insert:
INSERT INTO lecture
( member_id, major_id, semester, `name`, credit, `type`, ref_books, goal, weekly_plan, academic_year, max_std, start_date, end_date, room_id )
VALUES (
#{memberId},

(SELECT major_id FROM major WHERE name LIKE CONCAT('%', #{majorName}, '%') LIMIT 1), #{semester}, #{name}, #{credit}, #{type}, #{refBooks}, #{goal}, #{weeklyPlan}, #{academicYear}, #{maxStd}, #{startDate}, #{endDate}, #{roomId}
)

mapper.select:
SELECT room_id, building, room_number, capacity
FROM lecture_room
WHERE building = #{building}
